<!DOCTYPE html>
<html lang="pt-BR">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0, viewport-fit=cover">
<title>Yoru Shield VPN</title>
<style>
@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700;800;900&display=swap');

:root {
  --bg-main: #0a0e17;
  --bg-card: rgba(20, 25, 38, 0.6);
  --bg-card-solid: #131824;
  --border: rgba(255, 255, 255, 0.08);
  --text-main: #f8fafc;
  --text-muted: #94a3b8;
  --accent-blue: #3b82f6;
  --accent-indigo: #6366f1;
  --accent-cyan: #06b6d4;
  --success: #10b981;
  --warning: #f59e0b;
  --danger: #ef4444;
  --nav-h: 75px;
  --glass-blur: blur(12px);
}

* { box-sizing: border-box; -webkit-tap-highlight-color: transparent; margin: 0; padding: 0; }
html, body { min-height: 100%; background: var(--bg-main); }

body {
  font-family: 'Outfit', system-ui, sans-serif;
  color: var(--text-main);
  overflow-x: hidden;
  background-image: 
    radial-gradient(circle at 15% 50%, rgba(99, 102, 241, 0.08), transparent 25%),
    radial-gradient(circle at 85% 30%, rgba(6, 182, 212, 0.08), transparent 25%);
}

button { cursor: pointer; touch-action: manipulation; user-select: none; border: none; background: none; font-family: inherit; }

.app-shell {
  width: min(100%, 480px); margin: 0 auto;
  min-height: 100vh;
  display: flex; flex-direction: column;
  padding-bottom: calc(var(--nav-h) + env(safe-area-inset-bottom) + 20px);
}

/* HEADER YORU SHIELD */
.app-header {
  display: flex; justify-content: space-between; align-items: center;
  padding: 20px 24px;
}
.app-logo {
  font-size: 24px; font-weight: 900; letter-spacing: -0.5px;
  background: linear-gradient(135deg, #fff, #a5b4fc);
  -webkit-background-clip: text; -webkit-text-fill-color: transparent;
  display: flex; align-items: center; gap: 8px;
}
.app-logo-icon {
  width: 28px; height: 28px; border-radius: 8px;
  background: linear-gradient(135deg, var(--accent-indigo), var(--accent-cyan));
  display: grid; place-items: center; color: #fff; font-size: 14px;
  box-shadow: 0 4px 12px rgba(99, 102, 241, 0.3);
}
.app-version {
  font-size: 11px; font-weight: 700; color: var(--text-muted);
  background: rgba(255,255,255,0.05); padding: 4px 10px; border-radius: 20px;
  border: 1px solid var(--border);
}

/* PAGES */
.page { display: none; flex-direction: column; flex: 1; padding: 0 20px; animation: fadeIn 0.3s ease; }
.page.active { display: flex; }
@keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }

.page-title-box { margin-bottom: 20px; }
.page-title { font-size: 28px; font-weight: 800; color: #fff; }
.page-subtitle { font-size: 14px; color: var(--text-muted); font-weight: 400; margin-top: 4px; }

/* HERO - ORB (HOME) */
.hero-area {
  display: flex; flex-direction: column; align-items: center;
  margin-top: 20px; margin-bottom: 40px;
}

.orb-wrap { position: relative; width: 200px; height: 200px; margin-bottom: 24px; }

.orb-ring-outer {
  position: absolute; inset: 0; border-radius: 50%;
  background: conic-gradient(from 0deg, var(--border), rgba(99, 102, 241, 0.2), var(--border));
  padding: 2px;
}
.orb-ring-outer::before { content: ''; position: absolute; inset: 2px; border-radius: 50%; background: var(--bg-main); }

.orb-btn {
  position: absolute; inset: 15px; border-radius: 50%;
  background: linear-gradient(135deg, #2b3245, #1a2033);
  display: grid; place-items: center;
  box-shadow: 0 10px 30px rgba(0,0,0,0.5), inset 0 2px 0 rgba(255,255,255,0.1);
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  border: 1px solid rgba(255,255,255,0.05); cursor: pointer; z-index: 2;
}
.orb-btn:active { transform: scale(0.95); box-shadow: 0 5px 15px rgba(0,0,0,0.5); }
.orb-btn svg { width: 48px; height: 48px; color: var(--text-muted); transition: color 0.3s; }

/* ORB STATES */
body.st-conectado .orb-btn {
  background: linear-gradient(135deg, #10b981, #059669);
  box-shadow: 0 0 40px rgba(16, 185, 129, 0.3), inset 0 2px 0 rgba(255,255,255,0.2);
  border-color: rgba(255,255,255,0.2);
}
body.st-conectado .orb-btn svg { color: #fff; }
body.st-conectado .orb-ring-outer { background: conic-gradient(from 0deg, rgba(16, 185, 129, 0.1), rgba(16, 185, 129, 0.5), rgba(16, 185, 129, 0.1)); animation: spin 3s linear infinite; }

body.st-conectando .orb-btn {
  background: linear-gradient(135deg, #f59e0b, #d97706);
  box-shadow: 0 0 40px rgba(245, 158, 11, 0.3), inset 0 2px 0 rgba(255,255,255,0.2);
}
body.st-conectando .orb-btn svg { color: #fff; }
body.st-conectando .orb-ring-outer { background: conic-gradient(from 0deg, rgba(245, 158, 11, 0.1), rgba(245, 158, 11, 0.8), rgba(245, 158, 11, 0.1)); animation: spin 1s linear infinite; }

body.st-erro .orb-btn {
  background: linear-gradient(135deg, #ef4444, #dc2626);
  box-shadow: 0 0 40px rgba(239, 68, 68, 0.3);
}
body.st-erro .orb-btn svg { color: #fff; }

@keyframes spin { to { transform: rotate(360deg); } }

.status-title { font-size: 24px; font-weight: 800; text-align: center; color: var(--text-main); transition: color 0.3s; margin-bottom: 4px; }
body.st-conectado .status-title { color: var(--success); }
body.st-conectando .status-title { color: var(--warning); }
body.st-erro .status-title { color: var(--danger); }

.status-sub { font-size: 14px; color: var(--text-muted); text-align: center; font-weight: 400; max-width: 80%; }

.timer-bar {
  display: none; align-items: center; justify-content: center; gap: 8px;
  margin-top: 16px; padding: 8px 20px; border-radius: 100px;
  background: rgba(16, 185, 129, 0.1); border: 1px solid rgba(16, 185, 129, 0.2);
}
.timer-bar.show { display: flex; }
.timer-label { color: var(--success); font-weight: 700; font-size: 11px; letter-spacing: 1px; text-transform: uppercase; }
.timer-val { color: var(--success); font-weight: 800; font-size: 16px; font-variant-numeric: tabular-nums; }

/* METHOD PILL */
.method-pill-wrap { display: flex; justify-content: center; margin-top: 16px; }
.method-pill-btn {
  display: inline-flex; align-items: center; gap: 8px;
  padding: 8px 16px; border-radius: 100px;
  background: var(--bg-card); border: 1px solid var(--border);
  color: var(--text-main); font-size: 12px; font-weight: 700;
  cursor: pointer; transition: background 0.2s; backdrop-filter: var(--glass-blur);
}
.method-pill-btn:active { background: rgba(255,255,255,0.05); }
.method-pill-btn span:first-child { color: var(--accent-indigo); }

/* CARDS PADRÃO */
.yoru-card {
  background: var(--bg-card); border-radius: 20px;
  padding: 16px; border: 1px solid var(--border);
  backdrop-filter: var(--glass-blur); margin-bottom: 12px;
}
.server-card { display: flex; align-items: center; gap: 16px; cursor: pointer; transition: transform 0.2s; }
.server-card:active { transform: scale(0.98); }
.sc-icon {
  width: 48px; height: 48px; border-radius: 14px;
  background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.05);
  display: grid; place-items: center; font-size: 20px; overflow: hidden; flex-shrink: 0;
}
.sc-icon img { width: 100%; height: 100%; object-fit: cover; }
.sc-meta { flex: 1; min-width: 0; }
.sc-label { font-size: 10px; font-weight: 700; color: var(--accent-cyan); letter-spacing: 1px; text-transform: uppercase; margin-bottom: 2px; }
.sc-title { font-size: 16px; font-weight: 700; color: #fff; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.sc-sub { font-size: 12px; color: var(--text-muted); margin-top: 2px; font-weight: 500; }
.sc-chev { color: var(--text-muted); font-size: 20px; }

/* MESSAGES */
.message-card { display: none; align-items: center; gap: 14px; background: rgba(245, 158, 11, 0.05); border-color: rgba(245, 158, 11, 0.2); }
.message-card.show { display: flex; }
.msg-icon { font-size: 22px; }
.msg-title { font-size: 11px; font-weight: 800; letter-spacing: 1px; text-transform: uppercase; color: var(--warning); }
.msg-text { font-size: 13px; color: rgba(255,255,255,0.9); margin-top: 2px; line-height: 1.4; }

/* LISTA DE SERVIDORES (ABA 2) */
.list-item {
  display: flex; align-items: center; gap: 14px;
  padding: 16px; border-radius: 18px; margin-bottom: 10px;
  background: var(--bg-card); border: 1px solid var(--border);
  cursor: pointer; transition: all 0.2s;
}
.list-item:active { transform: scale(0.98); }
.list-item.selected { border-color: var(--accent-indigo); background: rgba(99, 102, 241, 0.1); }
.li-icon {
  width: 44px; height: 44px; border-radius: 12px; display: grid; place-items: center;
  background: rgba(255,255,255,0.05); overflow: hidden; font-size: 20px; flex-shrink: 0;
}
.li-icon img { width: 100%; height: 100%; object-fit: cover; }
.li-main { flex: 1; min-width: 0; }
.li-title { font-weight: 700; font-size: 15px; color: #fff; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.li-sub { color: var(--text-muted); font-size: 12px; margin-top: 2px; font-weight: 500; }
.li-check { color: var(--accent-indigo); display: none; font-size: 20px; font-weight: 900; }
.list-item.selected .li-check { display: block; }

/* DASHBOARD / PERFIL (ABA 3) */
.dashboard-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-bottom: 12px; }

.speed-card { background: var(--bg-card); border-radius: 20px; padding: 16px; border: 1px solid var(--border); }
.speed-label { font-size: 11px; font-weight: 700; color: var(--text-muted); text-transform: uppercase; letter-spacing: 1px; display: flex; align-items: center; gap: 6px;}
.speed-val { font-size: 22px; font-weight: 800; margin-top: 8px; color: #fff; font-variant-numeric: tabular-nums; }
.c-dl { color: var(--accent-cyan); } .c-ul { color: var(--success); }

.checkuser-card { display: none; }
.checkuser-card.show { display: block; }
.cu-title { font-size: 12px; font-weight: 800; letter-spacing: 1px; text-transform: uppercase; color: #fff; margin-bottom: 14px; display: flex; align-items: center; gap: 8px; }
.cu-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.cu-item { background: rgba(255,255,255,0.02); padding: 10px; border-radius: 12px; }
.cu-item-label { font-size: 11px; color: var(--text-muted); font-weight: 600; text-transform: uppercase; }
.cu-item-value { font-size: 14px; font-weight: 700; color: #fff; margin-top: 4px; }
.cu-item-value.green { color: var(--success); }

.time-card { display: none; border-color: rgba(245, 158, 11, 0.2); }
.time-card.show { display: block; }
.time-card-head { display: flex; align-items: center; justify-content: space-between; margin-bottom: 12px; }
.time-card-title { font-size: 11px; font-weight: 800; letter-spacing: 1px; text-transform: uppercase; color: var(--warning); }
.time-remaining { font-size: 22px; font-weight: 800; font-variant-numeric: tabular-nums; color: var(--warning); }
.time-bar-track { height: 6px; background: rgba(255,255,255,0.05); border-radius: 10px; overflow: hidden; margin-bottom: 16px; }
.time-bar-fill { height: 100%; background: linear-gradient(90deg, var(--warning), #ea580c); border-radius: 10px; transition: width 0.5s; }
.watch-ad-btn {
  width: 100%; padding: 14px; border-radius: 14px;
  background: rgba(245, 158, 11, 0.1); border: 1px solid rgba(245, 158, 11, 0.2);
  color: var(--warning); font-size: 14px; font-weight: 700; cursor: pointer; transition: all 0.2s;
}
.watch-ad-btn:active { background: rgba(245, 158, 11, 0.2); }
.watch-ad-btn:disabled { opacity: 0.5; cursor: not-allowed; }

/* TOOLS / ACTIONS */
.action-list { display: flex; flex-direction: column; gap: 8px; }
.action-btn {
  display: flex; align-items: center; justify-content: space-between;
  padding: 16px; border-radius: 16px; background: var(--bg-card);
  border: 1px solid var(--border); cursor: pointer; transition: transform 0.2s;
}
.action-btn:active { transform: scale(0.98); }
.ab-left { display: flex; align-items: center; gap: 12px; }
.ab-icon { width: 36px; height: 36px; border-radius: 10px; background: rgba(255,255,255,0.05); display: grid; place-items: center; font-size: 16px; }
.ab-text { font-size: 14px; font-weight: 600; color: #fff; }
.ab-chev { color: var(--text-muted); font-size: 18px; }

/* BOTTOM NAVIGATION (FLUTUANTE) */
.bottom-nav {
  position: fixed; bottom: 20px; left: 50%; transform: translateX(-50%);
  width: min(calc(100% - 40px), 400px);
  height: var(--nav-h);
  background: rgba(15, 20, 30, 0.85);
  backdrop-filter: blur(16px); -webkit-backdrop-filter: blur(16px);
  border: 1px solid rgba(255,255,255,0.08);
  border-radius: 24px;
  display: grid; grid-template-columns: repeat(4, 1fr);
  z-index: 50; box-shadow: 0 10px 40px rgba(0,0,0,0.5);
  padding: 0 8px;
}
.nav-btn {
  display: flex; flex-direction: column; align-items: center; justify-content: center;
  gap: 4px; color: var(--text-muted); font-size: 10px; font-weight: 700;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1); border-radius: 16px;
  margin: 6px 4px;
}
.nav-btn svg { width: 22px; height: 22px; stroke-width: 2.5; transition: transform 0.3s; }
.nav-btn.active { color: var(--text-main); background: rgba(255,255,255,0.05); }
.nav-btn.active svg { color: var(--accent-indigo); transform: translateY(-2px); }

/* MODAIS */
.modal-mask {
  position: fixed; inset: 0; z-index: 80;
  display: flex; align-items: flex-end; justify-content: center;
  background: rgba(0,0,0,0.7); backdrop-filter: blur(4px);
  opacity: 0; pointer-events: none; transition: 0.3s;
}
.modal-mask.show { opacity: 1; pointer-events: auto; }
.modal-box {
  display: none; flex-direction: column;
  width: 100%; max-width: 480px; max-height: 85vh;
  border-radius: 28px 28px 0 0;
  background: var(--bg-card-solid); border-top: 1px solid var(--border);
  overflow: hidden;
  transform: translateY(100%); transition: transform 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}
.modal-mask.show .modal-box.active { display: flex; transform: translateY(0); }
.modal-drag-handle { width: 40px; height: 5px; background: rgba(255,255,255,0.15); border-radius: 5px; margin: 12px auto; }
.modal-head { display: flex; align-items: center; justify-content: space-between; padding: 0 24px 16px; border-bottom: 1px solid var(--border); }
.modal-title { font-weight: 800; font-size: 18px; color: #fff; }
.icon-btn { width: 36px; height: 36px; border-radius: 12px; background: rgba(255,255,255,0.05); color: var(--text-muted); display: grid; place-items: center; font-size: 20px; }
.icon-btn:active { background: rgba(255,255,255,0.1); }
.modal-body { padding: 20px 24px; overflow-y: auto; flex: 1; }

/* METHOD MODAL SPECIFIC */
.method-list { display: flex; flex-direction: column; gap: 12px; }
.method-item {
  border-radius: 16px; padding: 16px;
  background: rgba(255,255,255,0.02); border: 1px solid var(--border);
  cursor: pointer; display: flex; align-items: center; justify-content: space-between;
}
.method-item.active-method { background: rgba(99, 102, 241, 0.1); border-color: var(--accent-indigo); }
.method-item.active-method .mi-title { color: var(--accent-indigo); }
.mi-title { font-size: 16px; font-weight: 700; color: #fff; }
.mi-sub { font-size: 12px; color: var(--text-muted); margin-top: 4px; }
.mi-radio { width: 20px; height: 20px; border-radius: 50%; border: 2px solid var(--text-muted); display: grid; place-items: center; }
.method-item.active-method .mi-radio { border-color: var(--accent-indigo); }
.method-item.active-method .mi-radio::after { content: ''; width: 10px; height: 10px; background: var(--accent-indigo); border-radius: 50%; }

/* CREDS MODAL SPECIFIC */
.creds-section-title { font-size: 11px; font-weight: 800; color: var(--text-muted); text-transform: uppercase; letter-spacing: 1px; margin: 16px 0 8px; }
.creds-input-wrap {
  background: rgba(0,0,0,0.2); border-radius: 14px;
  border: 1px solid var(--border); display: flex; align-items: center; gap: 12px;
  padding: 14px 16px; margin-bottom: 12px; transition: border 0.2s;
}
.creds-input-wrap:focus-within { border-color: var(--accent-indigo); }
.creds-input-wrap input { flex: 1; background: none; border: none; outline: none; color: #fff; font-size: 15px; font-family: inherit; }
.ci-icon { color: var(--text-muted); font-size: 18px; }
.ci-eye { color: var(--text-muted); font-size: 18px; }
.creds-save-btn {
  width: 100%; padding: 16px; border-radius: 16px; margin-top: 20px;
  background: var(--accent-indigo); color: #fff; font-size: 15px; font-weight: 700;
}

/* LOGS MODAL */
.logs-toolbar { display: flex; gap: 10px; justify-content: flex-end; margin-bottom: 16px; }
.log-action-btn { padding: 8px 16px; border-radius: 12px; font-size: 12px; font-weight: 700; background: rgba(255,255,255,0.05); color: #fff; }
.log-action-btn.danger { background: rgba(239, 68, 68, 0.1); color: var(--danger); }
#log-container { font-family: 'Courier New', monospace; font-size: 12px; line-height: 1.6; background: rgba(0,0,0,0.3); padding: 12px; border-radius: 16px; min-height: 200px; }
.log-entry { padding: 4px 0; border-bottom: 1px solid rgba(255,255,255,0.02); display: flex; gap: 8px; }
.log-entry.INFO { color: #fff; }
.log-entry.DEBUG { color: var(--accent-cyan); }
.log-entry.WARNING { color: var(--warning); }
.log-entry.ERROR { color: var(--danger); }
.log-time { color: var(--text-muted); opacity: 0.7; }

/* TOAST */
.toast-box { position: fixed; z-index: 120; left: 20px; right: 20px; top: 40px; display: grid; place-items: center; pointer-events: none; }
.toast {
  padding: 12px 20px; border-radius: 100px;
  background: rgba(15, 20, 30, 0.95); color: #fff;
  border: 1px solid var(--border); font-size: 13px; font-weight: 600;
  opacity: 0; transform: translateY(-20px); transition: 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  box-shadow: 0 10px 30px rgba(0,0,0,0.5); backdrop-filter: blur(10px); display: flex; align-items: center; gap: 8px;
}
.toast.show { opacity: 1; transform: translateY(0); }
.toast.ok { border-color: rgba(16, 185, 129, 0.4); }
.toast.err { border-color: rgba(239, 68, 68, 0.4); }
.toast.warn { border-color: rgba(245, 158, 11, 0.4); }

@media (max-width: 370px) {
  .orb-wrap { width: 160px; height: 160px; }
  .status-title { font-size: 20px; }
}
</style>
</head>
<body>
<div class="app-shell">

  <!-- HEADER GLOBAL -->
  <header class="app-header">
    <div class="app-logo">
      <div class="app-logo-icon">Y</div>
      Yoru Shield
    </div>
    <div class="app-version" id="config-version">v1.0</div>
  </header>

  <!-- ================= TELA 1: HOME (CONEXÃO) ================= -->
  <div class="page active" id="page-home">


    <div class="hero-area">
      <div class="orb-wrap">
        <div class="orb-ring-outer"></div>
        <button class="orb-btn" id="btn-connect">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <path d="M18.36 6.64a9 9 0 1 1-12.73 0"></path><line x1="12" y1="2" x2="12" y2="12"></line>
          </svg>
        </button>
      </div>
      <div class="status-title" id="status-label">Proteção pausada</div>
      <div class="status-sub" id="status-detail">Toque para iniciar uma sessão segura.</div>

      <div class="timer-bar" id="timer-bar">
        <span class="timer-label">Conectado há:</span>
        <span class="timer-val" id="timer-val">00:00</span>
      </div>



    </div>



    <!-- SELETORES RÁPIDOS -->
    <div class="server-card yoru-card" id="select-server">
      <div class="sc-icon" id="server-flag-wrap">🌍</div>
      <div class="sc-meta">
        <div class="sc-label">Operadora / Free</div>
        <div class="sc-title" id="server-title">Servidor Automático</div>
        <div class="sc-sub" id="server-sub">Selecionar rede</div>
      </div>
      <span class="sc-chev">›</span>
    </div>

    <div class="server-card yoru-card" id="select-premium" style="display:none;">
      <div class="sc-icon" id="premium-flag-wrap">💎</div>
      <div class="sc-meta">
        <div class="sc-label">Acesso Premium</div>
        <div class="sc-title" id="premium-title">Selecionar Servidor</div>
        <div class="sc-sub" id="premium-sub">Servidores VIPs</div>
      </div>
      <span class="sc-chev">›</span>
    </div>

  </div>

  <!-- ================= TELA 2: SERVIDORES ================= -->
  <div class="page" id="page-servers">
    <div class="page-title-box">
      <h2 class="page-title">Operadoras</h2>
      <p class="page-subtitle">Escolha a rede ideal para conexão</p>
    </div>
    <div id="list-servers-page" style="overflow-y: auto; padding-bottom: 20px;"></div>
  </div>


  <!-- ================= AVISOS ================= -->

    <div class="message-card yoru-card" id="message-card">
      <span class="msg-icon">📣</span>
      <div><div class="msg-title">Aviso</div><div class="msg-text" id="message-text"></div></div>
    </div>





  <!-- ================= TELA 3: PAINEL / PERFIL ================= -->
