<script>
(function () {
'use strict';

var A = {
  call: function (m, arg) {
    try {
      if (window.Android && typeof window.Android[m] === 'function')
        return arg !== undefined ? window.Android[m](arg) : window.Android[m]();
    } catch (e) { console.warn('Bridge.' + m, e); }
    return null;
  },
  parse: function (raw, fb) {
    try { return JSON.parse(raw) || fb; } catch (e) { return fb; }
  },
  connect:            function ()    { A.call('connect'); },
  getStatus:          function ()    { return A.call('getStatus') || 'DESCONECTADO'; },
  getServers:         function ()    { return A.parse(A.call('getServers'), []); },
  getSelected:        function ()    { return A.parse(A.call('getSelectedServer'), {}); },
  selectServer:       function (pos) { A.call('selectServer', pos); },
  getMultiServers:    function ()    { return A.parse(A.call('getMultiServers'), []); },
  getSelectedMulti:   function ()    { return A.parse(A.call('getSelectedMultiServer'), {}); },
  selectMultiServer:  function (pos) { A.call('selectMultiServer', pos); },
  getNote:            function ()    { return A.call('getNote') || ''; },
  getVersion:         function ()    { return A.call('getVersion') || ''; },
  getLogs:            function ()    { return A.parse(A.call('getLogs'), []); },
  clearLogs:          function ()    { A.call('clearLogs'); },
  openServers:        function ()    { A.call('openServers'); },
  checkUpdate:        function ()    { A.call('checkUpdate'); },
  requestInterstitial:function ()    { A.call('requestInterstitial'); },
  isAdsEnabled:       function ()    { return window.Android && typeof Android.isAdsEnabled === 'function' ? Android.isAdsEnabled() : false; },
  getTimeLeft:        function ()    { return window.Android && typeof Android.getTimeLeft === 'function' ? Android.getTimeLeft() : 0; },
  watchAd:            function ()    { A.call('watchAd'); }
};

var STATE = {
  CONECTADO:    { cls: 'st-conectado',   label: 'Protegido',         sub: 'Sua conexão está 100% segura e privada.', auth: 'ONLINE', authOk: true,  btn: 'DESCONECTAR' },
  DESCONECTADO: { cls: 'st-desconectado',label: 'Desprotegido',      sub: 'Toque no escudo para iniciar a VPN.', auth: '—',      authOk: false, btn: 'CONECTAR' },
  INICIANDO:    { cls: 'st-conectando',  label: 'Iniciando...',      sub: 'Preparando motor de conexão...', auth: '...',    authOk: false, btn: 'CANCELAR' },
  PARANDO:      { cls: 'st-conectando',  label: 'Parando...',        sub: 'Encerrando túnel seguro...', auth: '...',    authOk: false, btn: 'AGUARDE...' },
  CONECTANDO:   { cls: 'st-conectando',  label: 'Conectando...',     sub: 'Estabelecendo rota segura...', auth: '...',    authOk: false, btn: 'CANCELAR' },
  AGUARDANDO:   { cls: 'st-conectando',  label: 'Aguardando...',     sub: 'Negociando com o servidor...', auth: '...',    authOk: false, btn: 'CANCELAR' },
  AUTENTICANDO: { cls: 'st-conectando',  label: 'Autenticando...',   sub: 'Validando suas credenciais...', auth: '...',    authOk: false, btn: 'CANCELAR' },
  RECONECTANDO: { cls: 'st-conectando',  label: 'Reconectando...',   sub: 'Restaurando sinal perdido...', auth: '...',    authOk: false, btn: 'CANCELAR' },
  NOPROCESS:    { cls: '',               label: 'Desprotegido',      sub: 'Toque no escudo para iniciar a VPN.', auth: '—',      authOk: false, btn: 'CONECTAR' },
  ERRO:         { cls: 'st-erro',        label: 'Falha na conexão',  sub: 'Verifique sua internet ou credenciais.', auth: 'FALHA',  authOk: false, btn: 'TENTAR NOVAMENTE' }
};

var ALL_STATE_CLASSES = ['st-conectado', 'st-conectando', 'st-desconectado', 'st-erro'];
var app = { rawState: 'NOPROCESS', connected: false, busy: false, startedAt: 0, timerHandle: null, pollHandle: null, _mode: 'SSH' };

function $(id) { return document.getElementById(id); }
function setText(id, v) { var el = $(id); if (el) el.textContent = String(v == null ? '' : v); }
function pad(n) { return String(n).padStart(2, '0'); }
function esc(s) { return String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;'); }

function toast(msg, kind) {
  var el = $('toast'); if (!el) return;
  el.innerHTML = (kind === 'ok' ? '✅ ' : kind === 'err' ? '❌ ' : '⚠️ ') + msg;
  el.className = 'toast show ' + (kind ? kind : '');
  clearTimeout(el._t);
  el._t = setTimeout(function () { el.className = 'toast'; }, 3000);
}

window.showPage = function(name) {
  document.querySelectorAll('.page').forEach(function (p) { p.classList.remove('active'); });
  document.querySelectorAll('.nav-btn').forEach(function (b) { b.classList.remove('active'); });
  var pg = $('page-' + name); if (pg) pg.classList.add('active');
  var nb = $('nav-' + name); if (nb) nb.classList.add('active');
  if (name === 'servers') buildServerListPage();
}

function applyState(raw, detail) {
  raw = String(raw || 'NOPROCESS').toUpperCase().trim();
  app.rawState = raw;
  var s = STATE[raw] || STATE['NOPROCESS'];

  ALL_STATE_CLASSES.forEach(function (c) { document.body.classList.remove(c); });
  if (s.cls) document.body.classList.add(s.cls);

  setText('status-label', s.label);
  setText('status-detail', detail || s.sub);

  var slabel = $('speed-status-label'); if(slabel) slabel.textContent = s.label;

  var modePill = $('speed-mode-pill');
  if (modePill) modePill.textContent = (s.auth === 'ONLINE' ? '✓ ' : '') + app._mode;

  app.connected = (raw === 'CONECTADO');
  app.busy = ['INICIANDO','CONECTANDO','AUTENTICANDO','AGUARDANDO','RECONECTANDO','PARANDO'].indexOf(raw) >= 0;

  if (app.connected && !app.startedAt) { app.startedAt = Date.now(); startTimer(); }
  if (!app.connected && !app.busy) {
    if (app.startedAt) { app.startedAt = 0; stopTimer(); setText('timer-val','00:00'); }
    var tb = $('timer-bar'); if (tb) tb.classList.remove('show');
  }
}

function startTimer() {
  stopTimer();
  var tb = $('timer-bar'); if (tb) tb.classList.add('show');
  app.timerHandle = setInterval(function () {
    var sec = Math.floor((Date.now() - app.startedAt) / 1000);
    var h = Math.floor(sec / 3600), m = Math.floor((sec % 3600) / 60), s = sec % 60;
    setText('timer-val', (h ? pad(h) + ':' : '') + pad(m) + ':' + pad(s));
  }, 1000);
}
function stopTimer() { if (app.timerHandle) { clearInterval(app.timerHandle); app.timerHandle = null; } }

function startPolling() {
  app.pollHandle = setInterval(function () {
    var raw = A.getStatus();
    if (raw !== app.rawState) applyState(raw);
  }, 1200);
}

function renderLogs() {
  var container = $('log-container'); if (!container) return;
  var logs = A.getLogs();
  if (!logs || !logs.length) { container.innerHTML = '<div style="color:var(--text-muted);padding:8px">Nenhum log gerado ainda.</div>'; return; }
  var html = '';
  for (var i = logs.length - 1; i >= 0; i--) {
    var item = logs[i];
    var level = String(item.level || 'INFO').toUpperCase();
    var msg = esc(item.message || '');
    var time = item.time ? formatLogTime(item.time) : '';
    html += '<div class="log-entry ' + level + '"><span class="log-time">[' + esc(time) + ']</span><span class="log-msg">' + msg + '</span></div>';
  }
  container.innerHTML = html;
}

function formatLogTime(ms) {
  var d = new Date(ms); return pad(d.getHours()) + ':' + pad(d.getMinutes()) + ':' + pad(d.getSeconds());
}

function loadSavedCredentials() {
  try {
    var raw = window.Android && window.Android.getSavedCredentials ? window.Android.getSavedCredentials() : '{}';
    var creds = JSON.parse(raw);
    var fUser = $('ci-ssh-user'), fPass = $('ci-ssh-pass');
    var fUdp = $('ci-udp-token'), fV2 = $('ci-v2ray-uuid');
    if (fUser) fUser.value = creds.sshUser || '';
    if (fPass) fPass.value = creds.sshPass || '';
    if (fUdp)  fUdp.value  = creds.udpToken || '';
    if (fV2)   fV2.value   = creds.v2uuid || '';
  } catch (e) { console.warn('Erro ao carregar credenciais', e); }
}

function refreshInfo() {
  var ver = A.getVersion(); if (ver) setText('config-version', ver);
  var note = A.getNote();
  var mc = $('message-card'); if (mc) { mc.classList.toggle('show', !!note); setText('message-text', note); }
}

function refreshSelected() {
  var s = A.getSelected();
  if (s && s.Name) {
    setText('server-title', s.Name || 'Servidor Automático');
    setText('server-sub', s.Info || 'Pronto para uso');
    app._mode = s.Info || 'SSH';

    var mpill = $('speed-mode-pill'); if(mpill) mpill.textContent = s.Info || 'SSH';

    var wrap = $('server-flag-wrap');
    if (wrap && (s.FlagUrl || s.Flag)) {
      var src = s.FlagUrl ? s.FlagUrl : 'file:///android_asset/flags/' + s.Flag + '.png';
      wrap.innerHTML = '<img src="' + esc(src) + '" onerror="this.parentElement.innerHTML=\'🌍\'">';
    }
  }
  var p = A.getSelectedMulti();
  var pCard = $('select-premium');
  if (p && p.Name) {
    if (pCard) pCard.style.display = 'flex';
    setText('premium-title', p.Name || 'Selecionar Servidor');
    setText('premium-sub', p.Info || 'Acesso VIP');
    var pwrap = $('premium-flag-wrap');
    if (pwrap && (p.FlagUrl || p.Flag)) {
      var psrc = p.FlagUrl ? p.FlagUrl : 'file:///android_asset/flags/' + p.Flag + '.png';
      pwrap.innerHTML = '<img src="' + esc(psrc) + '" onerror="this.parentElement.innerHTML=\'💎\'">';
    }
  } else { if (pCard) pCard.style.display = 'none'; }
}

function buildServerList(type) {
  var root = $('list-servers'); if (!root) return;
  root.innerHTML = '';
  var isPremium = (type === 'premium');
  var servers  = isPremium ? A.getMultiServers() : A.getServers();
  var selected = isPremium ? A.getSelectedMulti() : A.getSelected();
  var selPos   = selected ? selected.position : -1;
  if (!servers || !servers.length) {
    root.innerHTML = '<div style="color:var(--text-muted);padding:20px;text-align:center;">Lista vazia ou não carregada.</div>';
    return;
  }
  var mTitleEl = document.querySelector('#modal-servers .modal-title');
  if (mTitleEl) mTitleEl.textContent = isPremium ? 'Redes Premium' : 'Redes Livres';

  servers.forEach(function (s, i) {
    var isSel   = (s.position === selPos || i === selPos);
    var flagSrc = s.FlagUrl ? s.FlagUrl : (s.Flag ? 'file:///android_asset/flags/' + s.Flag + '.png' : '');
    var el = document.createElement('div');
    el.className = 'list-item' + (isSel ? ' selected' : '');
    el.innerHTML = '<div class="li-icon">' + (flagSrc ? '<img src="' + esc(flagSrc) + '" onerror="this.parentElement.innerHTML=\'' + (isPremium ? '💎' : '🌍') + '\'">' : (isPremium ? '💎' : '🌍')) + '</div>' +
      '<div class="li-main"><div class="li-title">' + esc(s.Name || 'Rede') + '</div><div class="li-sub">' + esc(s.Info || (isPremium ? 'VIP' : 'Direct')) + '</div></div>' +
      '<span class="li-check">✓</span>';
    el.onclick = function () {
      if (app.connected) { toast('Desconecte para trocar de rede.', 'err'); return; }
      isPremium ? A.selectMultiServer(s.position !== undefined ? s.position : i) : A.selectServer(s.position !== undefined ? s.position : i);
      closeModal();
      setTimeout(function () { refreshSelected(); }, 250);
      toast(isPremium ? 'Rede VIP ativada!' : 'Rede selecionada!', 'ok');
    };
    root.appendChild(el);
  });
}

function buildServerListPage() {
  var root = $('list-servers-page'); if (!root) return;
