  }
  servers.forEach(function (s, i) {
    var isSel   = (s.position === selPos || i === selPos);
    var flagSrc = s.FlagUrl ? s.FlagUrl : (s.Flag ? 'file:///android_asset/flags/' + s.Flag + '.png' : '');
    var el = document.createElement('div');
    el.className = 'list-item' + (isSel ? ' selected' : '');
