/* Tempo restante */
var MAX_FREE_MS = 999999999, timeCard = null, timeFillEl = null, timeValEl = null, timeHandle = null, baseTimeMs = 0;
function initTimeCard() {
  timeCard   = $('time-card');
  timeFillEl = $('time-bar-fill');
  timeValEl  = $('time-remaining-val');
  var adsOn = A.isAdsEnabled();
  var left  = A.getTimeLeft();
  if (!adsOn || left >= MAX_FREE_MS) { if (timeCard) timeCard.classList.remove('show'); return; }
  if (timeCard) timeCard.classList.add('show');
  baseTimeMs = 7200000;
  updateTimeDisplay(left); startTimeCountdown(left);
}
function startTimeCountdown(ms) {
  if (timeHandle) clearInterval(timeHandle);
  var remaining = ms;
  timeHandle = setInterval(function () {
    remaining -= 1000;
    if (remaining <= 0) {
      remaining = 0; clearInterval(timeHandle);
      if (app.connected) A.connect();
      updateTimeDisplay(0);
      toast('Sessão expirada. Assista a um anúncio.', 'warn');
    }
    updateTimeDisplay(remaining);
  }, 1000);
}
function updateTimeDisplay(ms) {
  if (!timeValEl) return;
  if (ms <= 0) { timeValEl.textContent = '00:00'; if (timeFillEl) timeFillEl.style.width = '0%'; return; }
  var totalSec = Math.floor(ms / 1000), h = Math.floor(totalSec / 3600), m = Math.floor((totalSec % 3600) / 60), s = totalSec % 60;
  timeValEl.textContent = (h ? pad(h) + ':' : '') + pad(m) + ':' + pad(s);
  if (timeFillEl) {
    var pct = Math.min(100, (ms / baseTimeMs) * 100);
    timeFillEl.style.width = pct + '%';
    timeFillEl.style.background = pct < 20 ? 'linear-gradient(90deg, #ef4444, #f59e0b)' : 'linear-gradient(90deg, #f59e0b, #ea580c)';
  }
}

/* Callbacks do Android */
window.onVpnStatus       = function (raw, detail) { applyState(raw, detail || ''); };
window.onShowInterstitial= function () { A.requestInterstitial(); };
window.onCheckUserReceived = function (data) {
  var card = $('checkuser-card'); if (!card) return;
  card.classList.add('show');
  var u = typeof data === 'string' ? JSON.parse(data) : data;
  setText('cu-username',    u.username || '—');
  setText('cu-connections', (u.count_connection || '—') + ' / ' + (u.limiter_user || '—'));
  setText('cu-expiration',  u.expiration_date || '—');
  setText('cu-days',        (u.expiration_days || '—') + ' dias ativos');
};

/* Bridge original envia dados para os spans, garantimos que eles se atualizem */
setInterval(function() {
    var dl = $('speed-dl'); var dl_b = $('speed-dl-big');
    if(dl && dl_b && dl.textContent !== dl_b.textContent) { dl_b.textContent = dl.textContent; }
    var ul = $('speed-ul'); var ul_b = $('speed-ul-big');
    if(ul && ul_b && ul.textContent !== ul_b.textContent) { ul_b.textContent = ul.textContent; }
}, 1000);

window.onLogAdded = function (itemJson) {
  var container = $('log-container'); if (!container) return;
  try {
    var item  = typeof itemJson === 'string' ? JSON.parse(itemJson) : itemJson;
    var level = String(item.level || 'INFO').toUpperCase();
    var time  = item.time ? formatLogTime(item.time) : '';
    var div   = document.createElement('div');
    div.className = 'log-entry ' + level;
    div.innerHTML = '<span class="log-time">[' + esc(time) + ']</span> <span class="log-msg">' + esc(item.message || '') + '</span>';
    container.insertBefore(div, container.firstChild);
  } catch (e) {}
};
window.onLogsCleared  = function () { var c = $('log-container'); if (c) c.innerHTML = ''; };
window.onServerChanged= function () { refreshSelected(); var pg = $('page-servers'); if (pg && pg.classList.contains('active')) buildServerListPage(); };
window.onConfigUpdated= function () { refreshInfo(); refreshSelected(); toast('Dados em nuvem sincronizados!', 'ok'); };
window.onAdLoading    = function () { var btn = $('btn-watch-ad'); if (btn) { btn.textContent = 'Carregando publicidade...'; btn.disabled = true; } };
window.onTimeAdded    = function (newTotalMs) {
  if (timeHandle) clearInterval(timeHandle);
  updateTimeDisplay(newTotalMs); startTimeCountdown(newTotalMs);
  baseTimeMs = Math.max(baseTimeMs, 7200000);
  var btn = $('btn-watch-ad'); if (btn) { btn.textContent = 'Assistir Anúncio (+2 Horas)'; btn.disabled = false; }
  toast('+2 Horas concedidas!', 'ok');
};
window.onAdFailed = function () {
  var btn = $('btn-watch-ad'); if (btn) { btn.textContent = 'Assistir Anúncio (+2 Horas)'; btn.disabled = false; }
  toast('Anúncio falhou. Verifique a internet.', 'err');
};

/* Método */
var currentMethod = 'SSH';
window.selectMethod = function(m) {
  currentMethod = m;
  setText('method-pill-label', m);
  ['SSH','XRAY','V2RAY'].forEach(function (key) {
    var el = $('method-' + key.toLowerCase());
    if (el) el.classList.toggle('active-method', key === m);
  });
  if (window.Android && typeof Android.setMethod === 'function') Android.setMethod(m);
  closeModal();
  toast('Protocolo alterado para ' + m, 'ok');
}

window.toggleCiPass = function(id) {
  var f = $(id); if (!f) return;
  f.type = f.type === 'password' ? 'text' : 'password';
}

function bind() {
  var btnConn = $('btn-connect');
  if(btnConn) btnConn.onclick = function () {
    var raw = app.rawState; if (raw === 'PARANDO') return;
    A.connect();
    if (raw === 'CONECTADO') applyState('PARANDO', 'Encerrando túnel...');
    else if (['INICIANDO','CONECTANDO','AUTENTICANDO','AGUARDANDO','RECONECTANDO'].indexOf(raw) < 0)
      applyState('INICIANDO', 'Preparando conexão...');
  };

  var btnMeth = $('btn-open-method');
  if(btnMeth) btnMeth.onclick = function () {
    ['SSH','XRAY','V2RAY'].forEach(function (key) {
      var el = $('method-' + key.toLowerCase());
      if (el) el.classList.toggle('active-method', key === currentMethod);
    });
    openModal('modal-method');
  };

  var sServ = $('select-server'); if(sServ) sServ.onclick = function () { buildServerList('normal');  openModal('modal-servers'); };
  var pCard = $('select-premium'); if (pCard) pCard.onclick = function () { buildServerList('premium'); openModal('modal-servers'); };

  var tCred = $('tool-creds'); if(tCred) tCred.onclick = function () { openCredsModal(); };
  var tUpd = $('tool-update'); if(tUpd) tUpd.onclick = function () { toast('Sincronizando...', ''); A.checkUpdate(); };
  var tLog = $('tool-logs'); if(tLog) tLog.onclick = function () { renderLogs(); openModal('modal-logs'); };

  var cSave = $('btn-creds-save');
  if(cSave) cSave.onclick = function () {
    var u   = $('ci-ssh-user').value   || '';
    var p   = $('ci-ssh-pass').value   || '';
    var udp = $('ci-udp-token').value  || '';
    var v2  = $('ci-v2ray-uuid').value || '';
    if (window.Android && typeof window.Android.saveCredentials === 'function') {
      window.Android.saveCredentials(u, p, udp, v2);
      closeModal();
      toast('Dados salvos com sucesso.', 'ok');
    } else {
      toast('Erro de comunicação do sistema.', 'err');
    }
  };

  var rLog = $('btn-refresh-logs'); if(rLog) rLog.onclick = function () { renderLogs(); };
  var cLog = $('btn-clear-logs'); if(cLog) cLog.onclick   = function () {
    A.clearLogs();
    var c = $('log-container'); if (c) c.innerHTML = '<div style="color:var(--text-muted);padding:8px">Registros limpos.</div>';
    toast('Memória cache limpa.', '');
  };

  document.querySelectorAll('.modal-close').forEach(function (b) { b.onclick = closeModal; });
  var mMask = $('modal-mask'); if(mMask) mMask.onclick = function (e) { if (e.target === $('modal-mask')) closeModal(); };

  var btnAd = $('btn-watch-ad');
  if (btnAd) btnAd.onclick = function () { btnAd.textContent = 'Aguarde...'; btnAd.disabled = true; A.watchAd(); };
}

function boot() {
  bind();
  initTimeCard();
  refreshInfo();
  refreshSelected();
  applyState(A.getStatus());
  startPolling();
  setInterval(refreshInfo, 15000);
}

if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', boot);
else boot();

})();
</script>
</body>
</html>
